#include<iostream>#include<vector>#include<algorithm>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        int n;        cin>>n;        vector<int>a(n);        for(int i=0;i<n;i++){            cin>>a[i];        }        int left=0;        ll alice_ate= 0;        int right=n-1;        ll bob_ate= 0;        int total_candies=0;                while (left<=right)        {            if(alice_ate<=bob_ate){                                alice_ate+=a[left];                left++;            }            else{                                bob_ate+=a[right];                right--;            }            if(alice_ate== bob_ate){                total_candies= left+ (n - 1 - right);            }        }       cout<< total_candies<<"\n";             }}